local LUIEffectObject = LxClass("LUIEffectObject", nil)
------------------------------------------------------------------
local CS = CS
local typeofUISorting = typeof(CS.YXUISorting)

local typeofBtObjectView = typeof(CardEHT.BtObjectView)
local typeOfSkeletonAnimation = typeof(Spine.Unity.SkeletonAnimation)


-----------------------------------------------------------------
function LUIEffectObject:LUIEffectObject(wndClass)
	---@type LWnd
	self._wndClass = wndClass
	---@type LDisplayEffect
	self._displayEffect = nil

	self._startTime = 0
	self._playTime = 0

	self._isPlaying = nil
	self._isFinished = nil

	self._parentTrans = nil

	self._effectName = nil
	self._scaleSize = 1
	self._index = 0
	self._sortIndex = nil
	self._preLoadedCall = nil

	self._pool = nil
end

function LUIEffectObject:EnablePool(pool)
	self._pool = pool
end

function LUIEffectObject:Create(parentTrans, effectName, scaleSize, index, sortIndex, preLoadedCall,unscale,resType)
	self._parentTrans = parentTrans
	self._effectName = effectName
	self._scaleSize = scaleSize or 1
	self._index = index or 0
	self._sortIndex = sortIndex
	self._unscale = unscale

	self._resType = resType or 1

	self._preLoadedCall = preLoadedCall

	if self._resType ==1 then
		self:LoadEffect()
	else
		self:LoadSpine()
	end

