	--	end
	--	self:OnLoaded()
	--end)
end

function LUIEffectObject:LoadEffect()
	local dpEff = LDisplayEffect:New()
	self._displayEffect = dpEff
	dpEff:CreateEffect(self._parentTrans, self._effectName)
	dpEff:SetPool(self._pool)
	dpEff:SetUsePool(self._pool ~= nil)

	dpEff:SetLoadedFunction(function()
		if self._unscale~= nil then
			dpEff:ResetPlayState(self._unscale)
		end
		self:OnLoaded()
	end)
end

function LUIEffectObject:LoadSpine()
	local dpEff = LDisplaySpine:New()
	self._displayEffect = dpEff
	dpEff:CreateImpl(self._parentTrans, self._effectName)
	dpEff:SetPool(self._pool)
	dpEff:SetUsePool(self._pool ~= nil)

	dpEff:SetLoadedFunction(function()
		if self._unscale~= nil then
			dpEff:SetIgnoreTimeScale(self._unscale)
		end
		self:OnLoaded()
	end)
end


function LUIEffectObject:SetPos(pos)
	self._pos = pos
	self:InnerSetPosition(pos)
end

function LUIEffectObject:InnerSetPosition(pos)
	if not self._displayEffect:IsDpValid() then return end
	local dpTrans = self._displayEffect:GetDisplayTrans()
	dpTrans.localPosition = Vector3(pos.x,pos.y,pos.y * 0.01)
end

function LUIEffectObject:GetDisplayEffect()
	return self._displayEffect
end

------------------------------------------------------------------
function LUIEffectObject:SetBullet(isBullet,bulletTarPos,bulletFlyTime,bulletTrack, index)
	self._isBullet = isBullet
	self._bulletTarPos = bulletTarPos
	self._bulletFlyTime = bulletFlyTime
	self._bulletTrack = bulletTrack or 0
	self._bulletIndex = index or 0
end

function LUIEffectObject:CalcCurvePos(traceType,tarPos,bulletTarPos)
	if(traceType == 1) then
		return self:CalcCurvePosOne(tarPos,bulletTarPos)
	elseif(traceType == 2) then
		return self:CalcCurvePosTwo(tarPos,bulletTarPos)
	end
	return tarPos,bulletTarPos
end

function LUIEffectObject:CalcCurvePosOne(tarPos,bulletTarPos)
	local topPosX = Mathf.Lerp(tarPos.x , bulletTarPos.x,  2 / 3)
	local topPosY = Mathf.Lerp(tarPos.y , bulletTarPos.y,  0.5)
	local offectY = Vector3.Distance(tarPos, bulletTarPos)
	local topPos = Vector3(topPosX,topPosY + offectY,0)
	return topPos,bulletTarPos
end

function LUIEffectObject:CalcCurvePosTwo(tarPos,bulletTarPos)
	local topPosX = Mathf.Lerp(tarPos.x , bulletTarPos.x,  1 / 2)
	local topPosY = Mathf.Lerp(tarPos.y , bulletTarPos.y,  0.5)
	local offectY
	local isUp = self._bulletIndex % 2 == 1
	if isUp then
		offectY = math.random(0,15) * 0.1
	else
		offectY = math.random(-15,0) * 0.1
	end

	local topPos = Vector3(topPosX,topPosY + offectY,0)

	return topPos,bulletTarPos
end

-----------------------------------------------------------------
function LUIEffectObject:UpdateEffectSorting()
	local dpEff = self._displayEffect
	if not dpEff or not dpEff:IsDpValid() then return end
	if not self._sortIndex then return end
	local wndClass = self._wndClass
	local layer = wndClass:GetWndSortLayer()
	local order = wndClass:GetWndSortOrder()

	local dpParentTrans = dpEff:GetDisplayTrans()
	if dpParentTrans and CS.IsValidObject(dpParentTrans) then
		local rendererSort = dpParentTrans:GetComponent(typeofUISorting)
		if not rendererSort then
			rendererSort = dpParentTrans.gameObject:AddComponent(typeofUISorting)
		end

		rendererSort:SetLayerName(layer)
		rendererSort:SetParentOrder(order)
		rendererSort:SetInitOrder(self._sortIndex)
		rendererSort:SetCheckInitValue(true)
		rendererSort:UpdateSorting()
	end



end

function LUIEffectObject:AddUIParticleMask()
	local dpEff = self._displayEffect
	if not dpEff or not dpEff:IsDpValid() then return end
	local dpTrans = dpEff:GetDisplayTrans()
	local dpGo = dpTrans.gameObject
	CS.AddUIParticleMask(dpGo)
end
-----------------------------------------------------------------
function LUIEffectObject:OnLoaded()
	local dpEff = self._displayEffect
	if not dpEff or not dpEff:IsDpValid() then return end

	local dpTrans = dpEff:GetDisplayTrans()
	if self._pos then
		self:InnerSetPosition(self._pos)
	else
		self:InnerSetPosition(Vector3.zero)
	end

	dpTrans.name = self._effectName

	if self._resType == 1 then
		dpEff:SetEffectScale(self._scaleSize)
	else
		dpEff:SetScale(self._scaleSize)
	end

	local dpGo = dpTrans.gameObject
	if dpGo.layer ~= LWnd.WND_LAYER then
		CS.UpdateChildLayer(dpTrans, LWnd.WND_LAYER)
	end

	if self._sortIndex then
		self:UpdateEffectSorting()
	end

	if not self._isPlaying then
		dpEff:SetVisible(false)
	else
		self._displayEffect:SetVisible(true)
		self:InitBullet()
	end

	local preLoadedCall= self._preLoadedCall
	if preLoadedCall then
		preLoadedCall(self)
	end
end

LUIEffectObject.BULLET_SCALE_TYPE = {
	[LSkillEffConst.BULLET_LINEAR_THREE] = true,
	[LSkillEffConst.BULLET_NOANGLE_LINEAR_THREE] = true,
}

function LUIEffectObject:InitTweenMove(tweenPos, tweenTime, funEnd)
	local dpEff = self._displayEffect
	if not dpEff or not dpEff:IsDpValid() then return end
	local dpTrans = dpEff:GetDisplayTrans()
	local tween = dpTrans:DOLocalMove(tweenPos, tweenTime)
	tween:OnComplete(function()
		self._tween = nil
		if funEnd then
			funEnd(self)
		end
	end)
	self._tween = tween
	tween:PlayForward()
end

function LUIEffectObject:InitTweenScale(tweenScale, tweenTime, funEnd)
	local dpEff = self._displayEffect
	if not dpEff or not dpEff:IsDpValid() then return end
	local dpTrans = dpEff:GetDisplayTrans()
	local tween = dpTrans:DOScale(tweenScale, tweenTime)
	tween:OnComplete(function()
		self._tweenScale = nil
		if funEnd then
			funEnd(self)
		end
	end)
	self._tweenScale = tween
	tween:PlayForward()
end

function LUIEffectObject:InitBullet()
	--子弹
	if not self._isBullet then
		return
	end

	local dpEff = self._displayEffect
	if not dpEff or not dpEff:IsDpValid() then return end

	local dpTrans = dpEff:GetDisplayTrans()

	local comp = dpTrans:GetComponent(typeofBtObjectView)
	if not comp then
		comp = dpTrans.gameObject:AddComponent(typeofBtObjectView)
	end
	local time = self:GetTime()
	local calcTime = time - self._startTime
	local flyTime = self._bulletFlyTime
	local bulletTarPos = self._bulletTarPos

	local bulletTrack = self._bulletTrack
	if bulletTrack >= 100 then --100以上是不带z旋转的
		comp:EnableAngle(false)
	else
		comp:EnableAngle(true)
	end

	if LUIEffectObject.BULLET_SCALE_TYPE[bulletTrack] then
		comp:EnableScale(true,2.4)
	end

	if bulletTrack == LSkillEffConst.BULLET_LINEAR or bulletTrack == LSkillEffConst.BULLET_NOANGLE_LINEAR or
			bulletTrack == LSkillEffConst.BULLET_LINEAR_THREE or bulletTrack == LSkillEffConst.BULLET_NOANGLE_LINEAR_THREE then
		comp:StartMove(bulletTarPos,flyTime,calcTime)
	else
		local traceType
		if bulletTrack == LSkillEffConst.BULLET_CURVE_ONE or bulletTrack == LSkillEffConst.BULLET_NOANGLE_CURVE_ONE then
			traceType = 1
		elseif bulletTrack == LSkillEffConst.BULLET_CURVE_TWO or bulletTrack == LSkillEffConst.BULLET_NOANGLE_CURVE_TWO then
			traceType = 2
		end

		local tarPos = dpTrans.position
		local topPos,bulletTarPos = self:CalcCurvePos(traceType,tarPos,bulletTarPos)
		comp:StartJump(bulletTarPos, topPos, flyTime, calcTime)

		if calcTime > 0 then
			--为了让角度平滑 过度，预演 前一帧位置
			local t = 1
			if flyTime > 0 then t = calcTime / flyTime end
			t = t - 0.03
			if t < 0 then t = 0 end
			dpTrans.localPosition = comp:GetPoint(t)
		end
	end

	comp:UpdatePos()
end

-----------------------------------------------------------------
function LUIEffectObject:StartLoad()
	if not self._displayEffect then return end
	self._displayEffect:StartLoad()
end

-----------------------------------------------------------------
function LUIEffectObject:ResetEffect()
	if not self._displayEffect or not self._displayEffect:IsDpValid() then return end
	local dpTrans = self._displayEffect:GetDisplayTrans()
	if not self._skeletonAniList  then
		self._skeletonAniList = dpTrans:GetComponentsInChildren(typeOfSkeletonAnimation, true)
	end
	local skeletonAniLength = self._skeletonAniList.Length
	for k= 1,skeletonAniLength do
		local skeletonAni = self._skeletonAniList[k-1]
		local aniName = skeletonAni.AnimationName
		local animationState = skeletonAni.AnimationState
		if not animationState then
			break
		end
		animationState:SetAnimation(0, aniName, false)
	end
end

