------------------------------------------------------------------
function LUIEffectObject:StartPlay(startTime, endTime)
	self._startTime = startTime
	self._playTime = endTime
	self._isPlaying = false
	self._isFinished = false
	self._curTime = startTime
end

function LUIEffectObject:GetTime()
	return self._curTime
end

function LUIEffectObject:OnRun(time)
	self._curTime = time
	if self._isDestroy then return end
	if self._isFinished then return end
	if not self._isPlaying then
		if time >= self._startTime then
			self:OnStartPlay()
		end
	else
		if not self._isFinished and time > self._playTime then
			self._isFinished = true
			self._displayEffect:SetVisible(false)
		end
	end
	return true
end

function LUIEffectObject:OnStartPlay()
	self._isPlaying = true
	self._displayEffect:SetVisible(true)
	self:InitBullet()

	if self._resType == 2 then
		self._displayEffect:PlayAnimation(0,"show",false)
	end
end


-----------------------------------------------------------------
function LUIEffectObject:Destroy()
	if self._isDestroy then return end

	if self._tween then
		self._tween:Kill()
	end

	if self._tweenScale then
		self._tweenScale:Kill()
	end

	if self._displayEffect then
		self._displayEffect:Destroy()
		self._displayEffect = nil
	end
	table.removeall(self)
	self._isDestroy = true
end
------------------------------------------------------------------

return LUIEffectObject